"use client"

import { useEffect, useState } from "react"
import { useRouter } from "next/navigation"
import { useAuth } from "@/contexts/auth-context"
import { useTheme } from "@/contexts/theme-context"
import { Header } from "@/components/header"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover"
import {
  Command,
  CommandEmpty,
  CommandGroup,
  CommandInput,
  CommandItem,
  CommandList,
} from "@/components/ui/command"
import {
  Sidebar,
  SidebarContent,
  SidebarGroup,
  SidebarGroupContent,
  SidebarGroupLabel,
  SidebarMenu,
  SidebarMenuButton,
  SidebarMenuItem,
  SidebarProvider,
  SidebarHeader,
  SidebarInset,
  SidebarTrigger,
} from "@/components/ui/sidebar"
import { cn } from "@/lib/utils"
import { 
  Loader2, 
  Plus, 
  Trash2, 
  Save, 
  Eye,
  Palette,
  Type,
  LayoutDashboard,
  ArrowLeft,
  Upload,
  Check,
  Search,
  ChevronsUpDown,
  Package
} from "lucide-react"
import Link from "next/link"



interface PreviewTheme {
  name: string
  colors: {
    primary: string
    accent: string
    background: string
    foreground: string
  }
  font: string
  mode?: "light" | "dark" | "colorblind"
}

export default function AdminPage() {
  const { isAuthenticated, isAdmin, isLoading } = useAuth()
  const { customThemes, addCustomTheme, removeCustomTheme, updateCustomTheme, globalTypography, setGlobalTypography, customFonts, addCustomFont, removeCustomFont, applyTheme, modeThemeAssignment, setModeThemeAssignment } = useTheme()
  const router = useRouter()

  const [activeSection, setActiveSection] = useState<"colors" | "typography" | "inventory">("colors")
  const [newTheme, setNewTheme] = useState<PreviewTheme>({
    name: "",
    colors: {
      primary: "#dc4a1a",
      accent: "#dc4a1a",
      background: "#fafafa",
      foreground: "#1a1a1a",
    },
    font: "Geist",
  })
  const [selectedMode, setSelectedMode] = useState<"light" | "dark" | "colorblind">("light")

  const [previewTheme, setPreviewTheme] = useState<PreviewTheme | null>({
    name: "",
    colors: {
      primary: "#dc4a1a",
      accent: "#dc4a1a",
      background: "#fafafa",
      foreground: "#1a1a1a",
    },
    font: "Geist",
  })
  const [editingThemeId, setEditingThemeId] = useState<string | null>(null)
  const [themeSearchTerm, setThemeSearchTerm] = useState("")
  const [openLight, setOpenLight] = useState(false)
  const [openDark, setOpenDark] = useState(false)
  const [openColorblind, setOpenColorblind] = useState(false)
  const [openFontHeading, setOpenFontHeading] = useState(false)
  const [openFontBody, setOpenFontBody] = useState(false)
  const [newFontName, setNewFontName] = useState("")
  const [uploadingFont, setUploadingFont] = useState(false)
  const [fontSaved, setFontSaved] = useState(false)
  const [previewTypography, setPreviewTypography] = useState(globalTypography)

  // Sincronizar previewTypography cuando globalTypography cambia
  useEffect(() => {
    setPreviewTypography(globalTypography)
  }, [globalTypography])

  // Actualizar previsualización automáticamente cuando cambian los colores del formulario
  useEffect(() => {
    setPreviewTheme(newTheme)
  }, [newTheme])

  // Default font that cannot be deleted
  const defaultFont = { id: "default-geist", name: "Geist", fontFamily: "Geist", isDefault: true }
  
  // All fonts including default
  const allFonts = [defaultFont, ...customFonts.map(f => ({ ...f, isDefault: false }))]

  useEffect(() => {
    if (!isLoading && (!isAuthenticated || !isAdmin)) {
      router.push("/dashboard")
    }
  }, [isAuthenticated, isAdmin, isLoading, router])

  if (isLoading) {
    return (
      <div className="min-h-screen bg-background flex items-center justify-center">
        <Loader2 className="w-8 h-8 animate-spin text-primary" />
      </div>
    )
  }

  if (!isAuthenticated || !isAdmin) {
    return null
  }

  const handleAddTheme = () => {
    if (!newTheme.name.trim()) return

    if (editingThemeId) {
      updateCustomTheme(editingThemeId, {
        name: newTheme.name,
        colors: {
          primary: newTheme.colors.primary,
          accent: newTheme.colors.accent,
          background: newTheme.colors.background,
          foreground: newTheme.colors.foreground
        },
        font: newTheme.font
      })
      setEditingThemeId(null)
    } else {
      addCustomTheme({
        id: `custom-${Date.now()}`,
        name: newTheme.name,
        colors: {
          primary: newTheme.colors.primary,
          accent: newTheme.colors.accent,
          background: newTheme.colors.background,
          foreground: newTheme.colors.foreground
        },
        font: newTheme.font,
        mode: selectedMode,
      })
    }

    setNewTheme({
      name: "",
      colors: {
        primary: "#dc4a1a",
        accent: "#dc4a1a",
        background: "#fafafa",
        foreground: "#1a1a1a",
      },
      font: "Geist",
    })
    setSelectedMode("light")
  }

  const handleUpdateTheme = (id: string, updates: Partial<PreviewTheme>) => {
    updateCustomTheme(id, updates)
  }

  const startEditing = (theme: any) => {
    setEditingThemeId(theme.id)
    setNewTheme({
      name: theme.name,
      colors: { 
        primary: theme.colors.primary,
        accent: theme.colors.accent,
        background: theme.colors.background,
        foreground: theme.colors.foreground
      },
      font: theme.font || "Geist",
    })
    window.scrollTo({ top: 0, behavior: "smooth" })
  }

  const cancelEditing = () => {
    setEditingThemeId(null)
    setNewTheme({
      name: "",
      colors: {
        primary: "#dc4a1a",
        accent: "#dc4a1a",
        background: "#fafafa",
        foreground: "#1a1a1a",
      },
      font: "Geist",
    })
  }

  const handleFontUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0]
    if (!file || !newFontName.trim()) return

    setUploadingFont(true)

    try {
      const reader = new FileReader()
      reader.onload = (event) => {
        const dataUrl = event.target?.result as string
        const fontId = `custom-font-${Date.now()}`
        const fontFamily = newFontName.trim().replace(/\s+/g, "-")
        
        addCustomFont({
          id: fontId,
          name: newFontName.trim(),
          fontFamily: fontFamily,
          dataUrl: dataUrl,
        })

        setNewFontName("")
        setUploadingFont(false)
        e.target.value = ""
      }
      reader.onerror = () => {
        setUploadingFont(false)
      }
      reader.readAsDataURL(file)
    } catch {
      setUploadingFont(false)
    }
  }

  const handleSaveFont = () => {
    setGlobalTypography(previewTypography)
    setFontSaved(true)
    setTimeout(() => setFontSaved(false), 2000)
  }

  return (
    <SidebarProvider>
      <div className="flex min-h-screen w-full bg-background">
        <Sidebar className="border-r border-border bg-card">
          <SidebarHeader className="p-4 border-b border-border">
            <Link href="/dashboard" className="flex items-center justify-center">
              <img src="/logo_gear.png?v=2" alt="TruckParts Pro" className="h-8 w-auto object-contain" />
            </Link>
          </SidebarHeader>
          <SidebarContent>
            <SidebarGroup className="px-2 pt-4">
              <SidebarGroupLabel className="px-2 mb-4 text-[11px] font-black text-foreground uppercase tracking-widest">
                Gestión
              </SidebarGroupLabel>
              <SidebarGroupContent>
                <SidebarMenu className="gap-2">
                  <SidebarMenuItem>
                    <SidebarMenuButton
                      isActive={activeSection === "colors"}
                      onClick={() => setActiveSection("colors")}
                      className={cn(
                        "w-full flex items-center gap-3 px-3 py-2 rounded-md transition-all duration-200",
                        activeSection === "colors" 
                          ? "bg-accent/15 text-foreground font-bold" 
                          : "text-muted-foreground hover:bg-muted hover:text-foreground"
                      )}
                    >
                      <Palette className="h-5 w-5 shrink-0" />
                      <span className="text-[14px]">Colores</span>
                    </SidebarMenuButton>
                  </SidebarMenuItem>
                  <SidebarMenuItem>
                    <SidebarMenuButton
                      isActive={activeSection === "typography"}
                      onClick={() => setActiveSection("typography")}
                      className={cn(
                        "w-full flex items-center gap-3 px-3 py-2 rounded-md transition-all duration-200",
                        activeSection === "typography" 
                          ? "bg-accent/15 text-foreground font-bold" 
                          : "text-muted-foreground hover:bg-muted hover:text-foreground"
                      )}
                    >
                      <Type className="h-5 w-5 shrink-0" />
                      <span className="text-[14px]">Tipografía</span>
                    </SidebarMenuButton>
                  </SidebarMenuItem>
                  <SidebarMenuItem>
                    <SidebarMenuButton
                      isActive={activeSection === "inventory"}
                      onClick={() => setActiveSection("inventory")}
                      className={cn(
                        "w-full flex items-center gap-3 px-3 py-2 rounded-md transition-all duration-200",
                        activeSection === "inventory" 
                          ? "bg-accent/15 text-foreground font-bold" 
                          : "text-muted-foreground hover:bg-muted hover:text-foreground"
                      )}
                    >
                      <Package className="h-5 w-5 shrink-0" />
                      <span className="text-[14px]">Inventario</span>
                    </SidebarMenuButton>
                  </SidebarMenuItem>
                </SidebarMenu>
              </SidebarGroupContent>
            </SidebarGroup>
          </SidebarContent>
        </Sidebar>

        <SidebarInset className="flex-1 flex flex-col min-w-0 bg-background overflow-hidden">
          <header className="h-16 border-b border-border flex items-center justify-between px-6 bg-card/50 backdrop-blur-sm sticky top-0 z-10">
            <div className="flex items-center gap-4">
              <SidebarTrigger className="md:hidden" />
              <h2 className="text-xl font-bold flex items-center gap-2" style={{ color: newTheme.colors.primary }}>
                {activeSection === "colors" && <><Palette className="h-5 w-5" style={{ color: newTheme.colors.primary }} /> Gestión de Colores</>}
                {activeSection === "typography" && <><Type className="h-5 w-5" style={{ color: newTheme.colors.primary }} /> Gestión de Tipografía</>}
                {activeSection === "inventory" && <><Package className="h-5 w-5" style={{ color: newTheme.colors.primary }} /> Gestión de Inventario</>}
              </h2>
            </div>
            <div className="flex items-center gap-4">
              <Link href="/dashboard">
                <Button variant="outline" size="sm" className="hidden sm:flex items-center gap-2">
                  <ArrowLeft className="h-4 w-4" /> Volver al Sitio
                </Button>
              </Link>
            </div>
          </header>

          <main className="flex-1 overflow-y-auto p-6">
            <div className="grid lg:grid-cols-2 gap-8 max-w-7xl mx-auto">
              {/* Left Column - Form/List */}
              <div className="space-y-6">
                {activeSection === "colors" && (
                  <div className="space-y-6">
                    {/* Add New Theme */}
                    <Card className="bg-card border-border">
                      <CardHeader>
                        <CardTitle className="text-lg text-foreground flex items-center gap-2">
                          {editingThemeId ? <Palette className="h-5 w-5 text-primary" /> : <Plus className="h-5 w-5 text-primary" />}
                          {editingThemeId ? "Editar Tema" : "Crear Nuevo Tema"}
                        </CardTitle>
                        <CardDescription>
                          {editingThemeId ? "Modifica los colores de este tema" : "Define una nueva paleta de colores para la aplicación"}
                        </CardDescription>
                      </CardHeader>
                      <CardContent className="space-y-4">
                        <div className="space-y-2">
                          <Label htmlFor="themeName" className="text-foreground">Nombre del Tema</Label>
                          <Input
                            id="themeName"
                            placeholder="Mi tema personalizado"
                            value={newTheme.name}
                            onChange={(e) => setNewTheme({ ...newTheme, name: e.target.value })}
                            className="bg-input border-border text-foreground"
                          />
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                          <div className="space-y-2 col-span-2">
                            <Label className="text-foreground">Color Principal</Label>
                            <div className="flex gap-2">
                              <Input
                                type="color"
                                value={newTheme.colors.primary}
                                onChange={(e) => setNewTheme({
                                  ...newTheme,
                                  colors: { ...newTheme.colors, primary: e.target.value }
                                })}
                                className="w-12 h-10 p-1 cursor-pointer"
                              />
                              <Input
                                value={newTheme.colors.primary}
                                onChange={(e) => setNewTheme({
                                  ...newTheme,
                                  colors: { ...newTheme.colors, primary: e.target.value }
                                })}
                                className="bg-input border-border text-foreground flex-1"
                              />
                            </div>
                          </div>

                          <div className="space-y-2">
                            <Label className="text-foreground">Color de Acento</Label>
                            <div className="flex gap-2">
                              <Input
                                type="color"
                                value={newTheme.colors.accent}
                                onChange={(e) => setNewTheme({
                                  ...newTheme,
                                  colors: { ...newTheme.colors, accent: e.target.value }
                                })}
                                className="w-12 h-10 p-1 cursor-pointer"
                              />
                              <Input
                                value={newTheme.colors.accent}
                                onChange={(e) => setNewTheme({
                                  ...newTheme,
                                  colors: { ...newTheme.colors, accent: e.target.value }
                                })}
                                className="bg-input border-border text-foreground flex-1"
                              />
                            </div>
                          </div>

                          <div className="space-y-2">
                            <Label className="text-foreground">Fondo</Label>
                            <div className="flex gap-2">
                              <Input
                                type="color"
                                value={newTheme.colors.background}
                                onChange={(e) => setNewTheme({
                                  ...newTheme,
                                  colors: { ...newTheme.colors, background: e.target.value }
                                })}
                                className="w-12 h-10 p-1 cursor-pointer"
                              />
                              <Input
                                value={newTheme.colors.background}
                                onChange={(e) => setNewTheme({
                                  ...newTheme,
                                  colors: { ...newTheme.colors, background: e.target.value }
                                })}
                                className="bg-input border-border text-foreground flex-1"
                              />
                            </div>
                          </div>

                          <div className="space-y-2 col-span-2">
                            <Label className="text-foreground">Color de Texto</Label>
                            <div className="flex gap-2">
                              <Input
                                type="color"
                                value={newTheme.colors.foreground}
                                onChange={(e) => setNewTheme({
                                  ...newTheme,
                                  colors: { ...newTheme.colors, foreground: e.target.value }
                                })}
                                className="w-12 h-10 p-1 cursor-pointer"
                              />
                              <Input
                                value={newTheme.colors.foreground}
                                onChange={(e) => setNewTheme({
                                  ...newTheme,
                                  colors: { ...newTheme.colors, foreground: e.target.value }
                                })}
                                className="bg-input border-border text-foreground flex-1"
                              />
                            </div>
                          </div>

                          <div className="space-y-2 col-span-2">
                            <Label className="text-foreground">Modo de Tema</Label>
                            <div className="grid grid-cols-3 gap-2">
                              <Button
                                type="button"
                                variant={selectedMode === "light" ? "default" : "outline"}
                                onClick={() => setSelectedMode("light")}
                                className="text-xs"
                              >Claro</Button>
                              <Button
                                type="button"
                                variant={selectedMode === "dark" ? "default" : "outline"}
                                onClick={() => setSelectedMode("dark")}
                                className="text-xs"
                              >Oscuro</Button>
                              <Button
                                type="button"
                                variant={selectedMode === "colorblind" ? "default" : "outline"}
                                onClick={() => setSelectedMode("colorblind")}
                                className="text-xs"
                              >Daltónico</Button>
                            </div>
                          </div>
                        </div>

                        <div className="flex gap-2">
                          <Button
                            onClick={handleAddTheme}
                            disabled={!newTheme.name.trim()}
                            className="flex-1 text-white hover:opacity-90 transition-opacity"
                            style={{ backgroundColor: "var(--accent)" }}
                          >
                            {editingThemeId ? <Save className="mr-2 h-4 w-4" /> : <Plus className="mr-2 h-4 w-4" />}
                            {editingThemeId ? "Guardar Cambios" : "Agregar Tema"}
                          </Button>
                          {editingThemeId && (
                            <Button onClick={cancelEditing} variant="outline" className="border-border text-foreground">
                              Cancelar
                            </Button>
                          )}
                        </div>
                      </CardContent>
                    </Card>

                    {/* Mode Theme Assignment */}
                    <Card className="bg-card border-border">
                      <CardHeader>
                        <CardTitle className="text-lg text-foreground">Asignación de Temas por Modo</CardTitle>
                        <CardDescription>
                          Elige qué tema usar para cada modo de visualización
                        </CardDescription>
                      </CardHeader>
                      <CardContent className="space-y-4">
                        <div className="space-y-2">
                          <Label className="text-foreground">Tema para Modo Claro</Label>
                          <Popover open={openLight} onOpenChange={setOpenLight}>
                            <PopoverTrigger asChild>
                              <Button
                                variant="outline"
                                role="combobox"
                                aria-expanded={openLight}
                                className="w-full justify-between bg-input border-border text-foreground"
                              >
                                {modeThemeAssignment.light
                                  ? customThemes.find((theme) => theme.id === modeThemeAssignment.light)?.name
                                  : "Seleccionar tema..."}
                                <ChevronsUpDown className="ml-2 h-4 w-4 shrink-0 opacity-50" />
                              </Button>
                            </PopoverTrigger>
                            <PopoverContent className="w-full p-0 border-border">
                              <Command className="bg-card">
                                <CommandInput placeholder="Buscar tema..." className="h-9" />
                                <CommandList>
                                  <CommandEmpty>No se encontró ningún tema.</CommandEmpty>
                                  <CommandGroup>
                                    {customThemes
                                      .filter((t) => t.mode === "light")
                                      .map((theme) => (
                                        <CommandItem
                                          key={theme.id}
                                          value={theme.name}
                                          onSelect={() => {
                                            setModeThemeAssignment("light", theme.id)
                                            setOpenLight(false)
                                          }}
                                          className="cursor-pointer"
                                        >
                                          <Check
                                            className={cn(
                                              "mr-2 h-4 w-4",
                                              modeThemeAssignment.light === theme.id ? "opacity-100" : "opacity-0"
                                            )}
                                          />
                                          {theme.name}
                                        </CommandItem>
                                      ))}
                                  </CommandGroup>
                                </CommandList>
                              </Command>
                            </PopoverContent>
                          </Popover>
                        </div>

                        <div className="space-y-2">
                          <Label className="text-foreground">Tema para Modo Oscuro</Label>
                          <Popover open={openDark} onOpenChange={setOpenDark}>
                            <PopoverTrigger asChild>
                              <Button
                                variant="outline"
                                role="combobox"
                                aria-expanded={openDark}
                                className="w-full justify-between bg-input border-border text-foreground"
                              >
                                {modeThemeAssignment.dark
                                  ? customThemes.find((theme) => theme.id === modeThemeAssignment.dark)?.name
                                  : "Seleccionar tema..."}
                                <ChevronsUpDown className="ml-2 h-4 w-4 shrink-0 opacity-50" />
                              </Button>
                            </PopoverTrigger>
                            <PopoverContent className="w-full p-0 border-border">
                              <Command className="bg-card">
                                <CommandInput placeholder="Buscar tema..." className="h-9" />
                                <CommandList>
                                  <CommandEmpty>No se encontró ningún tema.</CommandEmpty>
                                  <CommandGroup>
                                    {customThemes
                                      .filter((t) => t.mode === "dark")
                                      .map((theme) => (
                                        <CommandItem
                                          key={theme.id}
                                          value={theme.name}
                                          onSelect={() => {
                                            setModeThemeAssignment("dark", theme.id)
                                            setOpenDark(false)
                                          }}
                                          className="cursor-pointer"
                                        >
                                          <Check
                                            className={cn(
                                              "mr-2 h-4 w-4",
                                              modeThemeAssignment.dark === theme.id ? "opacity-100" : "opacity-0"
                                            )}
                                          />
                                          {theme.name}
                                        </CommandItem>
                                      ))}
                                  </CommandGroup>
                                </CommandList>
                              </Command>
                            </PopoverContent>
                          </Popover>
                        </div>

                        <div className="space-y-2">
                          <Label className="text-foreground">Tema para Modo Daltónico</Label>
                          <Popover open={openColorblind} onOpenChange={setOpenColorblind}>
                            <PopoverTrigger asChild>
                              <Button
                                variant="outline"
                                role="combobox"
                                aria-expanded={openColorblind}
                                className="w-full justify-between bg-input border-border text-foreground"
                              >
                                {modeThemeAssignment.colorblind
                                  ? customThemes.find((theme) => theme.id === modeThemeAssignment.colorblind)?.name
                                  : "Seleccionar tema..."}
                                <ChevronsUpDown className="ml-2 h-4 w-4 shrink-0 opacity-50" />
                              </Button>
                            </PopoverTrigger>
                            <PopoverContent className="w-full p-0 border-border">
                              <Command className="bg-card">
                                <CommandInput placeholder="Buscar tema..." className="h-9" />
                                <CommandList>
                                  <CommandEmpty>No se encontró ningún tema.</CommandEmpty>
                                  <CommandGroup>
                                    {customThemes
                                      .filter((t) => t.mode === "colorblind")
                                      .map((theme) => (
                                        <CommandItem
                                          key={theme.id}
                                          value={theme.name}
                                          onSelect={() => {
                                            setModeThemeAssignment("colorblind", theme.id)
                                            setOpenColorblind(false)
                                          }}
                                          className="cursor-pointer"
                                        >
                                          <Check
                                            className={cn(
                                              "mr-2 h-4 w-4",
                                              modeThemeAssignment.colorblind === theme.id ? "opacity-100" : "opacity-0"
                                            )}
                                          />
                                          {theme.name}
                                        </CommandItem>
                                      ))}
                                  </CommandGroup>
                                </CommandList>
                              </Command>
                            </PopoverContent>
                          </Popover>
                        </div>
                      </CardContent>
                    </Card>

                    {/* Existing Themes */}
                    <Card className="bg-card border-border">
                      <CardHeader>
                        <div className="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
                          <div>
                            <CardTitle className="text-lg text-foreground">Temas Existentes</CardTitle>
                            <CardDescription>
                              Edita o elimina los temas personalizados
                            </CardDescription>
                          </div>
                          <div className="relative">
                            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground pointer-events-none" />
                            <Input
                              placeholder="Buscar temas..."
                              value={themeSearchTerm}
                              onChange={(e) => setThemeSearchTerm(e.target.value)}
                              className="pl-9 bg-input border-border text-foreground w-full sm:w-[250px]"
                            />
                          </div>
                        </div>
                      </CardHeader>
                      <CardContent className="space-y-3">
                        {customThemes.filter(t => t.name.toLowerCase().includes(themeSearchTerm.toLowerCase())).length === 0 ? (
                          <div className="p-8 text-center text-muted-foreground border border-dashed rounded-lg border-border">
                            No se encontraron temas que coincidan con "{themeSearchTerm}"
                          </div>
                        ) : (
                          customThemes
                            .filter(t => t.name.toLowerCase().includes(themeSearchTerm.toLowerCase()))
                            .map((theme) => (
                              <div
                                key={theme.id}
                                className="flex items-center justify-between p-4 bg-muted/50 rounded-lg border border-border transition-all cursor-pointer hover:border-primary/50"
                                onMouseEnter={() => setPreviewTheme({
                                  name: theme.name,
                                  colors: {
                                    primary: theme.colors.primary,
                                    accent: theme.colors.accent,
                                    background: theme.colors.background,
                                    foreground: theme.colors.foreground
                                  },
                                  font: theme.font || "Geist",
                                })}
                              >
                                <div className="flex items-center gap-4">
                                  <div className="flex gap-1">
                                    {Object.values(theme.colors).map((color, idx) => (
                                      <div
                                        key={idx}
                                        className="w-6 h-6 rounded-full border border-border"
                                        style={{ backgroundColor: color }}
                                      />
                                    ))}
                                  </div>
                                  <div>
                                    <p className="font-medium text-foreground">{theme.name}</p>
                                    <div className="flex gap-2 mt-1">
                                      <p className="text-xs text-muted-foreground">{theme.font}</p>
                                      {theme.mode && (
                                        <p className="text-xs text-foreground/70 font-semibold">
                                          {theme.mode === "light" && "• Claro"}
                                          {theme.mode === "dark" && "• Oscuro"}
                                          {theme.mode === "colorblind" && "• Daltónico"}
                                        </p>
                                      )}
                                      {theme.isDefault && (
                                        <p className="text-xs text-muted-foreground">Predeterminado</p>
                                      )}
                                    </div>
                                  </div>
                                </div>
                                <div className="flex gap-2">
                                  {editingThemeId !== theme.id && (
                                    <Button
                                      size="sm"
                                      variant="outline"
                                      onClick={() => startEditing(theme)}
                                      className="border-border text-foreground hover:bg-muted"
                                    >
                                      Editar
                                    </Button>
                                  )}
                                  <Button
                                    size="sm"
                                    variant="outline"
                                    onClick={() => applyTheme(theme)}
                                    className="border-border text-foreground hover:bg-muted"
                                  >
                                    Aplicar
                                  </Button>
                                  {!theme.id.startsWith("default-") && !Object.values(modeThemeAssignment).includes(theme.id as string) && (
                                    <Button
                                      size="sm"
                                      variant="destructive"
                                      onClick={() => removeCustomTheme(theme.id)}
                                    >
                                      <Trash2 className="h-4 w-4" />
                                    </Button>
                                  )}
                                  {!theme.id.startsWith("default-") && Object.values(modeThemeAssignment).includes(theme.id as string) && (
                                    <Button
                                      size="sm"
                                      variant="secondary"
                                      disabled
                                      title="No se puede eliminar porque está asignado a un modo"
                                    >
                                      <Trash2 className="h-4 w-4 opacity-50" />
                                    </Button>
                                  )}
                                </div>
                              </div>
                            ))
                        )}
                      </CardContent>
                    </Card>
                  </div>
                )}

                {activeSection === "typography" && (
                  <div className="space-y-6">
                    {/* Upload New Font */}
                    <Card className="bg-card border-border">
                      <CardHeader>
                        <CardTitle className="text-lg text-foreground flex items-center gap-2">
                          <Upload className="h-5 w-5 text-primary" />
                          Agregar Nueva Tipografía
                        </CardTitle>
                        <CardDescription>
                          Sube un archivo TTF para agregar una fuente personalizada
                        </CardDescription>
                      </CardHeader>
                      <CardContent className="space-y-4">
                        <div className="space-y-2">
                          <Label className="text-foreground">Nombre de la Fuente</Label>
                          <Input
                            placeholder="Ej: Mi Fuente Personalizada"
                            value={newFontName}
                            onChange={(e) => setNewFontName(e.target.value)}
                            className="bg-input border-border text-foreground"
                          />
                        </div>

                        <div className="space-y-2">
                          <Label className="text-foreground">Archivo TTF</Label>
                          <div className="flex gap-2">
                            <Input
                              type="file"
                              accept=".ttf,.otf,.woff,.woff2"
                              onChange={handleFontUpload}
                              disabled={!newFontName.trim() || uploadingFont}
                              className="bg-input border-border text-foreground file:text-white file:border-0 file:rounded file:px-3 file:py-1 file:mr-3 file:cursor-pointer file:hover:opacity-90"
                              style={{ "--accent-color": "var(--accent)" } as any}
                            />
                            <style dangerouslySetInnerHTML={{__html: `
                              input[type="file"]::file-selector-button {
                                background-color: var(--accent);
                              }
                            `}} />
                          </div>
                          {!newFontName.trim() && (
                            <p className="text-xs text-muted-foreground">
                              Primero ingresa un nombre para la fuente
                            </p>
                          )}
                          {uploadingFont && (
                            <div className="flex items-center gap-2 text-sm text-muted-foreground">
                              <Loader2 className="h-4 w-4 animate-spin" />
                              Subiendo fuente...
                            </div>
                          )}
                        </div>
                      </CardContent>
                    </Card>

                    {/* Configuración de Tipografía */}
                    <Card className="bg-card border-border">
                      <CardHeader>
                        <CardTitle className="text-lg text-foreground flex items-center gap-2">
                          <Type className="h-5 w-5 text-primary" />
                          Configurador de Tipografías
                        </CardTitle>
                        <CardDescription>
                          Asigna fuentes y tamaños para títulos y subtítulos
                        </CardDescription>
                      </CardHeader>
                      <CardContent className="space-y-6">
                        <div className="space-y-4">
                          <div className="space-y-2">
                            <Label className="text-foreground font-medium">Seleccionar fuente para TÍTULO (.ttf)</Label>
                            <Popover open={openFontHeading} onOpenChange={setOpenFontHeading}>
                              <PopoverTrigger asChild>
                                <Button
                                  variant="outline"
                                  role="combobox"
                                  aria-expanded={openFontHeading}
                                  className="w-full justify-between bg-input border-border text-foreground h-12"
                                >
                                  {previewTypography.headingFont
                                    ? allFonts.find((f) => f.fontFamily === previewTypography.headingFont)?.name
                                    : "Seleccionar fuente..."}
                                  <ChevronsUpDown className="ml-2 h-4 w-4 shrink-0 opacity-50" />
                                </Button>
                              </PopoverTrigger>
                              <PopoverContent className="w-[var(--radix-popover-trigger-width)] p-0 border-border">
                                <Command className="bg-card">
                                  <CommandInput placeholder="Buscar fuente..." className="h-9" />
                                  <CommandList>
                                    <CommandEmpty>No se encontró la fuente.</CommandEmpty>
                                    <CommandGroup>
                                      {allFonts.map((font) => (
                                        <CommandItem
                                          key={font.id}
                                          value={font.name}
                                          onSelect={() => {
                                            setPreviewTypography((p: any) => ({ ...p, headingFont: font.fontFamily }))
                                            setOpenFontHeading(false)
                                          }}
                                          className="cursor-pointer"
                                          style={{ fontFamily: font.fontFamily }}
                                        >
                                          <Check
                                            className={cn(
                                              "mr-2 h-4 w-4",
                                              previewTypography.headingFont === font.fontFamily ? "opacity-100" : "opacity-0"
                                            )}
                                          />
                                          {font.name}
                                        </CommandItem>
                                      ))}
                                    </CommandGroup>
                                  </CommandList>
                                </Command>
                              </PopoverContent>
                            </Popover>
                          </div>

                          <div className="space-y-2">
                            <Label className="text-foreground font-medium">Seleccionar fuente para SUBTÍTULO y PÁRRAFO (.ttf)</Label>
                            <Popover open={openFontBody} onOpenChange={setOpenFontBody}>
                              <PopoverTrigger asChild>
                                <Button
                                  variant="outline"
                                  role="combobox"
                                  aria-expanded={openFontBody}
                                  className="w-full justify-between bg-input border-border text-foreground h-12"
                                >
                                  {previewTypography.bodyFont
                                    ? allFonts.find((f) => f.fontFamily === previewTypography.bodyFont)?.name
                                    : "Seleccionar fuente..."}
                                  <ChevronsUpDown className="ml-2 h-4 w-4 shrink-0 opacity-50" />
                                </Button>
                              </PopoverTrigger>
                              <PopoverContent className="w-[var(--radix-popover-trigger-width)] p-0 border-border">
                                <Command className="bg-card">
                                  <CommandInput placeholder="Buscar fuente..." className="h-9" />
                                  <CommandList>
                                    <CommandEmpty>No se encontró la fuente.</CommandEmpty>
                                    <CommandGroup>
                                      {allFonts.map((font) => (
                                        <CommandItem
                                          key={font.id}
                                          value={font.name}
                                          onSelect={() => {
                                            setPreviewTypography((p: any) => ({ ...p, bodyFont: font.fontFamily }))
                                            setOpenFontBody(false)
                                          }}
                                          className="cursor-pointer"
                                          style={{ fontFamily: font.fontFamily }}
                                        >
                                          <Check
                                            className={cn(
                                              "mr-2 h-4 w-4",
                                              previewTypography.bodyFont === font.fontFamily ? "opacity-100" : "opacity-0"
                                            )}
                                          />
                                          {font.name}
                                        </CommandItem>
                                      ))}
                                    </CommandGroup>
                                  </CommandList>
                                </Command>
                              </PopoverContent>
                            </Popover>
                          </div>
                        </div>

                        <div className="pt-4 border-t border-border">
                          <div className="flex items-center gap-2 mb-4">
                            <Type className="h-5 w-5 text-primary" />
                            <h3 className="text-foreground font-bold">Tamaños de Fuente</h3>
                          </div>
                          
                          <div className="space-y-4">
                            <div className="space-y-2">
                              <Label className="text-foreground flex items-center gap-2">
                                <span className="font-bold">H</span> Titulo (px)
                              </Label>
                              <div className="flex items-center gap-2">
                                <Button 
                                  variant="outline" 
                                  size="icon" 
                                  className="h-10 w-10 border-border"
                                  onClick={() => setPreviewTypography((p: any) => ({ ...p, headingSize: (parseFloat(p.headingSize) - 0.1).toFixed(1) }))}
                                >
                                  -
                                </Button>
                                <Input
                                  type="number"
                                  step="0.1"
                                  value={previewTypography.headingSize}
                                  onChange={e => setPreviewTypography((p: any) => ({ ...p, headingSize: e.target.value }))}
                                  className="bg-input border-border text-foreground text-center"
                                />
                                <Button 
                                  variant="outline" 
                                  size="icon" 
                                  className="h-10 w-10 border-border"
                                  onClick={() => setPreviewTypography((p: any) => ({ ...p, headingSize: (parseFloat(p.headingSize) + 0.1).toFixed(1) }))}
                                >
                                  +
                                </Button>
                              </div>
                            </div>

                            <div className="space-y-2">
                              <Label className="text-foreground flex items-center gap-2">
                                <span className="font-bold">H</span> Subtitulo (px)
                              </Label>
                              <div className="flex items-center gap-2">
                                <Button 
                                  variant="outline" 
                                  size="icon" 
                                  className="h-10 w-10 border-border"
                                  onClick={() => setPreviewTypography((p: any) => ({ ...p, bodySize: (parseFloat(p.bodySize) - 0.1).toFixed(1) }))}
                                >
                                  -
                                </Button>
                                <Input
                                  type="number"
                                  step="0.1"
                                  value={previewTypography.bodySize}
                                  onChange={e => setPreviewTypography((p: any) => ({ ...p, bodySize: e.target.value }))}
                                  className="bg-input border-border text-foreground text-center"
                                />
                                <Button 
                                  variant="outline" 
                                  size="icon" 
                                  className="h-10 w-10 border-border"
                                  onClick={() => setPreviewTypography((p: any) => ({ ...p, bodySize: (parseFloat(p.bodySize) + 0.1).toFixed(1) }))}
                                >
                                  +
                                </Button>
                              </div>
                            </div>
                          </div>

                          <Button
                            onClick={handleSaveFont}
                            disabled={JSON.stringify(previewTypography) === JSON.stringify(globalTypography)}
                            className="w-full mt-6 text-white hover:opacity-90 transition-opacity"
                            style={{ backgroundColor: "var(--accent)" }}
                          >
                            {fontSaved ? (
                              <>
                                <Check className="mr-2 h-4 w-4" />
                                Guardado
                              </>
                            ) : (
                              <>
                                <Save className="mr-2 h-4 w-4" />
                                Guardar Tipografía
                              </>
                            )}
                          </Button>
                        </div>
                      </CardContent>
                    </Card>

                    {/* Font List */}
                    <Card className="bg-card border-border">
                      <CardHeader>
                        <CardTitle className="text-lg text-foreground flex items-center gap-2">
                          <Type className="h-5 w-5 text-primary" />
                          Mis Tipografías
                        </CardTitle>
                        <CardDescription>
                          Selecciona una fuente para previsualizarla y guarda para aplicarla
                        </CardDescription>
                      </CardHeader>
                      <CardContent className="space-y-4">
                        <div className="space-y-2 max-h-64 overflow-y-auto">
                          {allFonts.length === 0 ? (
                            <div className="p-8 text-center text-muted-foreground border border-dashed rounded-lg border-border">
                              No hay tipografías instaladas
                            </div>
                          ) : (
                            allFonts.map((font) => {
                              const isUsed = previewTypography.headingFont === font.fontFamily || previewTypography.bodyFont === font.fontFamily
                              return (
                                <div
                                  key={font.id}
                                  className={`flex items-center justify-between p-3 rounded-lg border transition-colors cursor-pointer ${
                                    isUsed
                                      ? "bg-primary/10 border-primary"
                                      : "bg-muted/50 border-border hover:bg-muted"
                                  }`}
                                >
                                    <div className="flex items-center gap-3">
                                      <div
                                        className={`w-4 h-4 rounded-full border-2 flex items-center justify-center ${
                                          isUsed
                                            ? "border-primary bg-primary"
                                            : "border-muted-foreground"
                                        }`}
                                      >
                                        {isUsed && (
                                          <Check className="h-3 w-3 text-primary-foreground" />
                                        )}
                                      </div>
                                      <div>
                                        <p className="font-medium text-foreground" style={{ fontFamily: font.fontFamily }}>
                                          {font.name}
                                        </p>
                                        {font.isDefault && (
                                          <p className="text-xs text-muted-foreground">Predeterminada</p>
                                        )}
                                      </div>
                                    </div>
                                  {!font.isDefault && (
                                    <Button
                                      size="sm"
                                      variant="destructive"
                                      onClick={(e) => {
                                        e.stopPropagation()
                                        removeCustomFont(font.id)
                                      }}
                                    >
                                      <Trash2 className="h-4 w-4" />
                                    </Button>
                                  )}
                                </div>
                              )})
                          )}
                        </div>
                      </CardContent>
                    </Card>
                  </div>
                )}

                {activeSection === "inventory" && (
                  <div className="space-y-6">
                    <Card className="bg-card border-border">
                      <CardHeader>
                        <div className="flex items-center justify-between">
                          <div>
                            <CardTitle className="text-lg text-foreground flex items-center gap-2">
                              <Package className="h-5 w-5 text-primary" />
                              Gestión de Inventario
                            </CardTitle>
                            <CardDescription>
                              Administra los productos y stock de la tienda
                            </CardDescription>
                          </div>
                          <Button className="bg-primary text-primary-foreground">
                            <Plus className="mr-2 h-4 w-4" /> Nuevo Producto
                          </Button>
                        </div>
                      </CardHeader>
                      <CardContent>
                        <div className="border border-dashed border-border rounded-lg p-12 text-center">
                          <Package className="h-12 w-12 text-muted-foreground mx-auto mb-4 opacity-20" />
                          <h3 className="text-lg font-medium text-foreground">El módulo de inventario está en desarrollo</h3>
                          <p className="text-muted-foreground mt-2 max-w-sm mx-auto">
                            Próximamente podrás agregar, editar y eliminar productos directamente desde aquí.
                          </p>
                        </div>
                      </CardContent>
                    </Card>
                  </div>
                )}
              </div>

              {/* Right Column - Live Preview */}
              <div className="lg:sticky lg:top-0 h-fit">
                <Card className="bg-card border-border overflow-hidden shadow-xl">
                  <CardHeader className="border-b border-border bg-muted/30">
                    <CardTitle className="text-lg text-foreground flex items-center gap-2">
                      <Eye className="h-5 w-5 text-primary" />
                      Previsualización en Vivo
                    </CardTitle>
                    <CardDescription>
                      Así se verá la aplicación con los cambios
                    </CardDescription>
                  </CardHeader>
                  <CardContent className="p-0">
                    <div
                      id="preview-container-root"
                      className="min-h-[600px] flex flex-col relative overflow-hidden"
                      style={{
                        backgroundColor: previewTheme?.colors.background || "#fafafa",
                        color: previewTheme?.colors.foreground || "#1a1a1a",
                        fontFamily: `'${previewTypography.bodyFont}', sans-serif`,
                      }}
                    >
                      {/* Dynamic CSS for Typography */}
                      <style dangerouslySetInnerHTML={{__html: `
                        #preview-container-root .font-heading,
                        #preview-container-root h1, 
                        #preview-container-root h2, 
                        #preview-container-root h3 {
                          font-family: '${previewTypography.headingFont}', sans-serif !important;
                          font-size: calc(24px * ${previewTypography.headingSize}) !important;
                          line-height: 1.2;
                        }
                        
                        #preview-container-root .subtitle,
                        #preview-container-root p,
                        #preview-container-root li,
                        #preview-container-root button {
                          font-family: '${previewTypography.bodyFont}', sans-serif;
                          font-size: calc(14px * ${previewTypography.bodySize}) !important;
                        }
                      `}} />

                      {/* Preview Header */}
                      <div 
                        className="p-4 border-b flex items-center justify-between"
                        style={{ 
                          backgroundColor: previewTheme?.colors.primary || "#dc4a1a",
                          borderColor: `${previewTheme?.colors.foreground || "#1a1a1a"}20`
                        }}
                      >
                        <span 
                          className="font-bold font-heading"
                          style={{ color: previewTheme?.colors.background || "#ffffff" }}
                        >
                          TruckPartsPro
                        </span>
                        <div className="flex gap-2">
                          <div className="w-2 h-2 rounded-full bg-current opacity-50" />
                          <div className="w-2 h-2 rounded-full bg-current opacity-50" />
                        </div>
                      </div>

                      <div className="flex-1 p-4">
                        {/* Preview Products */}
                        <div className="grid grid-cols-2 gap-3 mb-4">
                          {[1, 2].map((i) => (
                            <div
                              key={i}
                              className="p-3 rounded-lg border"
                              style={{
                                backgroundColor: `${previewTheme?.colors.primary || "#dc4a1a"}80`,
                                borderColor: previewTheme?.colors.accent || "#dc4a1a",
                                boxShadow: `0 0 12px 3px ${(previewTheme?.colors.accent || "#dc4a1a")}66`,
                              }}
                            >
                              <div
                                className="w-full aspect-square rounded mb-2 flex items-center justify-center"
                                style={{
                                  backgroundColor: previewTheme?.colors.background || "#fafafa",
                                }}
                              >
                                <span className="text-2xl opacity-30">📦</span>
                              </div>
                              <h4 className="subtitle font-medium mb-1">Subtítulo Producto {i}</h4>
                              <p
                                className="font-bold"
                                style={{ color: previewTheme?.colors.foreground || "#dc4a1a" }}
                              >
                                $199.99
                              </p>
                            </div>
                          ))}
                        </div>

                        {/* Preview Button */}
                        <button
                          className="w-full py-3 rounded-lg font-semibold mb-6"
                          style={{
                            backgroundColor: previewTheme?.colors.accent || "#dc4a1a",
                            color: previewTheme?.colors.background || "#ffffff",
                            boxShadow: `0 0 18px 6px ${(previewTheme?.colors.accent || "#dc4a1a")}66`,
                          }}
                        >
                          Ver Detalles
                        </button>

                        {/* Preview Footer */}
                        <div 
                          className="p-6 rounded-lg grid grid-cols-2 gap-4"
                          style={{ 
                            backgroundColor: previewTheme?.colors.primary || "#dc4a1a",
                            color: previewTheme?.colors.foreground || "#ffffff",
                          }}
                        >
                          <div className="space-y-4">
                            <div>
                              <h4 className="font-bold uppercase tracking-wider mb-2 opacity-60 font-heading">Enlaces</h4>
                              <ul className="space-y-1 opacity-90 subtitle" style={{ fontSize: '10px' }}>
                                <li>Inicio</li>
                                <li>Productos</li>
                              </ul>
                            </div>
                          </div>
                          <div>
                            <h4 className="font-bold uppercase tracking-wider mb-2 opacity-60 font-heading">Categorías</h4>
                            <ul className="space-y-1 opacity-90 subtitle" style={{ fontSize: '10px' }}>
                              <li>Motores</li>
                              <li>Frenos</li>
                            </ul>
                          </div>
                        </div>
                      </div>
                    </div>
                  </CardContent>
                </Card>
              </div>
            </div>
          </main>
        </SidebarInset>
      </div>
    </SidebarProvider>
  )
}
